    try:
        repo = connector.collection(Collections.PLUGIN_REPOS).find_one({"name": "Default"})
        if not repo:
            print("Creating the Default plugin repository...")
            repo = PluginRepoIn(
                name="Default",
                url=os.environ.get("GIT_URL", "https://github.com/netskopeoss/ta_cloud_exchange_plugins.git"),
                username=os.environ.get("GIT_USERNAME", ""),
                password=os.environ.get("GIT_PASSWORD", ""),
                isDefault=True,
            )
            connector = DBConnector()
            connector.collection(Collections.PLUGIN_REPOS).insert_one(repo.model_dump())
    except Exception as e:
        print("Error occurred while creating Default plugin repository. ",e)
        exit(1)

    # update plugin ids
